"use strict";var e={id:"hello-world",handler:e=>{e.get("/",(e,o)=>{o.json({message:"Hello World!",timestamp:(new Date).toISOString(),method:"GET"})}),e.get("/greet/:name",(e,o)=>{const{name:t}=e.params;o.json({message:`Hello, ${t}!`,timestamp:(new Date).toISOString()})}),e.get("/info",(e,o)=>{o.json({extension:"directus-extension-hello-world",version:"1.0.0",description:"Demo custom API endpoint",endpoints:["GET /hello-world","GET /hello-world/greet/:name","GET /hello-world/info"]})})}};module.exports=e;
